export function TribunalCourt({ engines }: { engines:EngineProgress[] }) {
  const rawElapsed = engines[0]?.elapsed ?? 0;
  const elapsed = Number.isFinite(rawElapsed) ? rawElapsed : 0;
  const frame = ((Math.floor(elapsed) % SCALES_FRAMES.length) + SCALES_FRAMES.length) % SCALES_FRAMES.length;
  const title = SCALES_FRAMES[frame];
  return (
    <Box flexDirection="column" paddingLeft={2}>
      <Text color="#c084fc" bold>{title}</Text>
      <Text color="#c084fc">{'\u2551'}</Text>
      {engines.map((e: EngineProgress) => {
        const status = String(e.status ?? '');
        const statusParts = status.split(' ');
        const round = statusParts[0] ?? '';
        const position = statusParts.slice(1).join(' ');
        const posColor = position.includes('pro') || position.includes('defender') ? '#22c55e'
          : position.includes('con') || position.includes('challenger') ? '#ef4444'
          : '#c084fc';
        return (
          <Box key={e.id}>
            <Text color="#c084fc">{'\u2551 '}</Text>
            <Text color={e.done ? 'green' : status === 'waiting' ? '#64748b' : 'yellow'}>
              {e.done ? '\u2713' : status === 'waiting' ? '\u25cb' : '\u25cf'}
            </Text>
            <Text>{' '}</Text>
            <Box width={14}>
              <Text bold color={engineColor(e.id)}>{e.id}</Text>
            </Box>
            {status === 'waiting' ? (
              <Text dimColor>{'awaiting turn'}</Text>
            ) : e.done ? (
              <Text color="green">{status}</Text>
            ) : (
              <Box>
                <Text dimColor>{round}{' '}</Text>
                <Text color={posColor} bold>{position}</Text>
              </Box>
            )}
            <Text color="#c084fc">{' \u2551'}</Text>
          </Box>
        );
      })}
      <Text color="#c084fc">{'\u2551'}</Text>
      <Text color="#c084fc" bold>{title}</Text>
    </Box>
  );
}

// @kern-source: arena:14
function forgeBar(pct: number, width: number): string {
  const safeWidth = Math.max(0, Math.floor(width));
  const safePct = Math.max(0, Math.min(1, pct));
  const filled = Math.round((safePct * safeWidth));
  const half = (safePct > 0 && filled < safeWidth) ? 1 : 0;
  const halfChar = half ? '▒' : '';
  return '█'.repeat(filled) + halfChar + '░'.repeat(Math.max(0, (safeWidth - filled - half)));
}

// @kern-source: arena:23
function forgeSummary(engines: EngineProgress[]): string {
  const doneCount = engines.filter((e: EngineProgress) => e.done).length;
  const failedCount = engines.filter((e: EngineProgress) => e.failed).length;
  const failedSuffix = failedCount ? (' · ' + failedCount + ' failed') : '';
  return ' ' + doneCount + '/' + engines.length + ' done' + failedSuffix;
}

// @kern-source: arena:30
function renderForgeRows(engines: EngineProgress[]): React.ReactNode {
  const maxElapsed = 120;
  const leader = engines.reduce((acc: { leaderId: string; bestPct: number }, e: EngineProgress) => {
    const status = String(e.status ?? '');
    const elapsed = Number.isFinite(e.elapsed) ? Math.max(0, e.elapsed) : 0;
    const active = !e.done && !e.failed && !status.startsWith('queued') && !status.startsWith('preparing') && !status.startsWith('waiting');
    const pct = e.done ? 1 : active ? Math.min(elapsed / maxElapsed, 0.9) : 0;
    return (pct > acc.bestPct || e.done) ? { leaderId: e.id, bestPct: pct } : acc;
  }, { leaderId: '', bestPct: -1 });
  return engines.map((e: EngineProgress) => {
    const status = String(e.status ?? '');
    const elapsed = Number.isFinite(e.elapsed) ? Math.max(0, e.elapsed) : 0;
    const isWaiting = status.startsWith('queued') || status.startsWith('preparing') || status.startsWith('waiting');
    const isActive = !e.done && !e.failed && !isWaiting;
    const pct = e.done ? 1 : e.failed ? 0 : isActive ? Math.min(elapsed / maxElapsed, 0.9) : 0;
    const bar = forgeBar(pct, 12);
    const isLead = e.id === leader.leaderId && !e.failed;
    const statusTxt = e.done ? (e.score ? `score ${e.score}` : 'done') : e.failed ? 'failed' : isWaiting ? status : `${status} ${Math.round(pct * 100)}%`;
    return (
      <Box key={e.id}>
        <Text color={e.done ? 'green' : e.failed ? 'red' : 'yellow'}>
          {e.done ? '\u2713' : e.failed ? '\u2717' : isWaiting ? '\u25e6' : isLead ? '\u25b8' : '\u00b7'}
        </Text>
        <Text>{' '}</Text>
        <Box width={16}>
          {e.isAgent ? <Text color="#fbbf24">{'\u26a1 '}</Text> : null}
          <Text bold color={engineColor(e.id)}>{e.id}</Text>
        </Box>
        <Text color={e.done ? '#22c55e' : e.failed ? '#ef4444' : '#f97316'}>{bar}</Text>
        <Text>{' '}</Text>
        <Text dimColor>{statusTxt}</Text>
      </Box>
    );
  });
}

